SELECT county_name 
FROM counties 
ORDER BY county_name;

SELECT SUM(age_0_to_14 + age_15_to_19 + age_20_to_29 + age_30_to_54 + age_55_to_64 + age_65_plus) AS total_population
FROM age_demographics
WHERE year = 2023;

SELECT MAX(year) 
FROM age_demographics 
WHERE county_id = 1;

SELECT county_name 
FROM counties 
ORDER BY county_name;
